def section_header(text, sub=None):
    sub_html = f'''<div style="font-family:Share Tech Mono,monospace;font-size:9px;
        letter-spacing:3px;color:#4a7a9a;margin-top:4px;text-transform:uppercase;">{sub}</div>''' if sub else ""
    st.markdown(f"""
    <div style="margin:24px 0 16px 0;padding-bottom:8px;
        border-bottom:1px solid rgba(120,200,255,0.1);">
        <div style="font-family:Titillium Web,sans-serif;font-weight:200;font-size:18px;
            letter-spacing:6px;text-transform:uppercase;color:#e8f4ff;
            text-shadow:0 0 20px rgba(120,200,255,0.3);">{text}</div>
        {sub_html}
    </div>
    """, unsafe_allow_html=True)

def apply_theme(fig, title_text=None):
    # Darker plot background
    fig.update_layout(
        plot_bgcolor='rgba(2,4,14,0.92)',
        paper_bgcolor='rgba(0,0,0,0)',
        font=dict(color='#8abedc', family='Share Tech Mono', size=10),
        legend=dict(font=dict(color='#8abedc', size=10),
            bgcolor='rgba(4,8,24,0.85)',
            bordercolor='rgba(120,200,255,0.2)', borderwidth=1),
        margin=dict(l=50,r=20,t=50,b=50),
    )
    if title_text:
        fig.update_layout(title=dict(text=title_text,
            font=dict(color='#c8ddf0', family='Titillium Web', size=13),
            x=0, xanchor='left'))
    # Bolder, more visible axes
    fig.update_xaxes(
        gridcolor='rgba(120,200,255,0.1)',
        zerolinecolor='rgba(120,200,255,0.2)',
        linecolor='rgba(120,200,255,0.35)',
        linewidth=1.5,
        color='#8abedc',
        tickfont=dict(size=10, color='#7aadda', family='Share Tech Mono'),
        title_font=dict(size=11, color='#8abedc', family='Share Tech Mono'),
    )
    fig.update_yaxes(
        gridcolor='rgba(120,200,255,0.1)',
        zerolinecolor='rgba(120,200,255,0.2)',
        linecolor='rgba(120,200,255,0.35)',
        linewidth=1.5,
        color='#8abedc',
        tickfont=dict(size=10, color='#7aadda', family='Share Tech Mono'),
        title_font=dict(size=11, color='#8abedc', family='Share Tech Mono'),
    )
    return fig

