if link_override != "Auto (Cycle)":
    loss_map = {"EXCELLENT":0.05,"GOOD":0.18,"FAIR":0.35,"POOR":0.55,"CRITICAL":0.75}
    lr = loss_map[link_override]
    try:
        ares_system.channel.solar_interference    = lr * 0.6
        ares_system.channel.atmospheric_noise     = lr * 0.3
        ares_system.channel.equipment_degradation = lr * 0.1
    except Exception:
        pass

